const n = parseInt(process.argv[2]);
let total = 0;
for (let i = 1; i <= n; i++) {
    let k = i;
    while (k !== 1) {
        if (k % 2 === 0) k = k / 2;
        else k = 3 * k + 1;
        total++;
    }
}
console.log(total);

const n = parseInt(process.argv[2]);
let count = 0;
for (let i = 2; i <= n; i++) {
    let isPrime = true;
    for (let d = 2; d * d <= i; d++) {
        if (i % d === 0) { isPrime = false; break; }
    }
    if (isPrime) count++;
}
console.log(count);

const limit = parseInt(process.argv[2]);
const sieve = new Uint8Array(limit + 1);
let count = 0;
for (let i = 2; i <= limit; i++) {
    if (!sieve[i]) {
        count++;
        for (let j = i * i; j <= limit; j += i)
            sieve[j] = 1;
    }
}
console.log(count);

function gcd(a, b) {
    while (b > 0) { const t = b; b = a % b; a = t; }
    return a;
}
const n = parseInt(process.argv[2]);
let sum = 0;
for (let i = 1; i <= n; i++)
    for (let j = i; j <= n; j++)
        sum += gcd(i, j);
console.log(sum);
